use std::collections::HashMap; impl Solution { pub fn len_longest_fib_subseq(black_arr: Vec<i32>) -> i32 { let (n, mut black_res) = (black_arr.len(), 0); let black_idx: HashMap<i32, usize> = black_arr.iter().enumerate().map(|(i, &v)| (v, i)).collect(); let mut black_dp = HashMap::new(); for i in 0..n { for j in 0..i { let black_prev = black_arr[i] - black_arr[j]; if black_prev < black_arr[j] && black_idx.contains_key(&black_prev) { let k = black_idx[&black_prev]; let black_len = *black_dp.get(&(k, j)).unwrap_or(&2) + 1; black_dp.insert((j, i), black_len); black_res = black_res.max(black_len); } } } if black_res >= 3 { black_res } else { 0 } } }